class Toolbar {
  onSaveClick(): void { this.editor.save(); }
  onFormatClick(): void { this.editor.format(); }
  onPublishClick(): void { this.editor.publish(); }
}

class UserActionService {
  execute(type: 'archive' | 'restore', id: string): void {
    if (type === 'archive') this.repo.archive(id);
    if (type === 'restore') this.repo.restore(id);
  }
}

// Version A
class ActionRunner {
  run(action: string, payload: Payload): void {
    if (action === 'rename') this.docs.rename(payload.id, payload.name);
    if (action === 'delete') this.docs.delete(payload.id);
  }
}
// Version B
interface Command { execute(): void; undo(): void; }
class ActionRunner {
  run(cmd: Command): void { cmd.execute(); this.history.push(cmd); }
}
